// Date handling for automation workflows

const items = $input.all();

return items.map(item => {
  const data = item.json;

  // Parse date string
  const createdDate = new Date(data.createdAt);
  const now = new Date();

  // Calculate differences
  const ageInMs = now - createdDate;
  const ageInDays = Math.floor(ageInMs / (1000 * 60 * 60 * 24));
  const ageInHours = Math.floor(ageInMs / (1000 * 60 * 60));

  // Format dates
  const formattedDate = createdDate.toISOString().split("T")[0]; // YYYY-MM-DD
  const formattedTime = createdDate.toTimeString().split(" ")[0]; // HH:MM:SS

  // Add/subtract time
  const dueDate = new Date(createdDate);
  dueDate.setDate(dueDate.getDate() + 7); // Add 7 days

  // Check conditions
  const isOverdue = now > dueDate;
  const isWeekend = [0, 6].includes(createdDate.getDay());

  return {
    json: {
      ...data,
      dateInfo: {
        original: data.createdAt,
        formatted: formattedDate,
        time: formattedTime,
        ageInDays: ageInDays,
        ageInHours: ageInHours,
        dueDate: dueDate.toISOString(),
        isOverdue: isOverdue,
        isWeekend: isWeekend,
        dayOfWeek: createdDate.toLocaleDateString("en-US", { weekday: "long" })
      }
    }
  };
});

