// ✅ GOOD - Separate concerns into functions

function calculateOrderTotal(items) {
  return items.reduce((sum, item) => sum + (item.price * item.quantity), 0);
}

function determineShippingTier(total) {
  if (total > 100) return "free";
  if (total > 50) return "reduced";
  return "standard";
}

function formatOrderSummary(order) {
  const total = calculateOrderTotal(order.items);
  const shipping = determineShippingTier(total);

  return {
    orderId: order.id,
    subtotal: total,
    shippingTier: shipping,
    estimatedTotal: shipping === "free" ? total : total + 9.99
  };
}

